from flask import Flask, request, jsonify
from kafka import KafkaProducer
import os
import atexit

app = Flask(__name__)

BOOTSTRAP_SERVERS = os.environ.get("KAFKA_BOOTSTRAP_SERVERS", "localhost:9092").split(",")
CLIENT_ID = os.environ.get("KAFKA_CLIENT_ID", "flexible-event-api-producer")

producer = KafkaProducer(
    bootstrap_servers=BOOTSTRAP_SERVERS,
    client_id=CLIENT_ID,
    acks=os.environ.get("KAFKA_ACKS", "1"),
    linger_ms=int(os.environ.get("KAFKA_LINGER_MS", "5")),
    retries=int(os.environ.get("KAFKA_RETRIES", "3")),
    max_in_flight_requests_per_connection=int(os.environ.get("KAFKA_MAX_IN_FLIGHT", "5")),
    value_serializer=lambda v: v if isinstance(v, (bytes, bytearray)) else str(v).encode("utf-8"),
    key_serializer=lambda v: v if v is None or isinstance(v, (bytes, bytearray)) else str(v).encode("utf-8"),
)

@atexit.register
def _close_producer():
    try:
        producer.flush(timeout=5)
    except Exception:
        pass
    try:
        producer.close(timeout=5)
    except Exception:
        pass

@app.route("/publish", methods=["POST", "GET"])
def publish():
    topic = request.args.get("topic") or request.form.get("topic") or (request.json or {}).get("topic")
    if not topic:
        return jsonify({"error": "missing 'topic' parameter"}), 400

    payload = request.get_data(cache=False, as_text=False) or b""
    if not payload and request.is_json:
        payload = str(request.get_json()).encode("utf-8")

    key = request.args.get("key") or request.form.get("key") or (request.json or {}).get("key")
    key_bytes = None if key is None else str(key).encode("utf-8")

    future = producer.send(topic, value=payload, key=key_bytes)

    wait = (request.args.get("wait") or "").lower() in ("1", "true", "yes")
    if wait:
        try:
            md = future.get(timeout=float(request.args.get("timeout", "10")))
            return jsonify({"topic": md.topic, "partition": md.partition, "offset": md.offset}), 200
        except Exception as e:
            return jsonify({"error": str(e)}), 500

    return jsonify({"status": "queued", "topic": topic}), 202

if __name__ == "__main__":
    host = os.environ.get("HOST", "0.0.0.0")
    port = int(os.environ.get("PORT", "8080"))
    app.run(host=host, port=port)